return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var rows = 3;
    var cols = 4;
    var radius = 15;
    var paddingX = (W - (cols - 1) * 60) / 2;
    var paddingY = (H - (rows - 1) * 55) / 2 + 10;

    function getPos(r, c) {
      return {
        x: paddingX + c * 60,
        y: paddingY + r * 55
      };
    }

    // Animation cycle (repeats every 6 seconds)
    var duration = 6000;
    var progress = (t % duration) / duration;
    var totalDots = rows * cols;

    // Dot drawing threshold
    var dotsToShow = Math.floor(progress * (totalDots + 3)); // overshoot a bit to pause at the end
    dotsToShow = Math.min(dotsToShow, totalDots);

    // Draw Grid dots
    for (var r = 0; r < rows; r++) {
      for (var c = 0; c < cols; c++) {
        var idx = r * cols + c;
        var pos = getPos(r, c);

        if (idx < dotsToShow) {
          // Pulse the active dots
          var isNewest = (idx === dotsToShow - 1 && dotsToShow < totalDots);
          var pulse = isNewest ? 4 * Math.sin(t * 0.02) : 0;

          ctx.fillStyle = '#EC4899'; // Coral-pink color for active dots
          ctx.beginPath();
          ctx.arc(pos.x, pos.y, radius + pulse, 0, Math.PI * 2);
          ctx.fill();

          // Overlay text inside dot
          ctx.fillStyle = '#FFFFFF';
          ctx.font = 'bold 11px -apple-system, sans-serif';
          ctx.textAlign = 'center';
          ctx.textBaseline = 'middle';
          ctx.fillText((idx + 1).toString(), pos.x, pos.y);
        } else {
          // Inactive dots placeholder
          ctx.strokeStyle = '#374151';
          ctx.lineWidth = 1.5;
          ctx.beginPath();
          ctx.arc(pos.x, pos.y, radius, 0, Math.PI * 2);
          ctx.stroke();
        }
      }
    }

    // Draw Row Groupings if full grid is active
    if (dotsToShow >= totalDots) {
      ctx.strokeStyle = '#3B82F6'; // Blue bounding boxes for rows
      ctx.lineWidth = 2.5;
      for (var r = 0; r < rows; r++) {
        var startPos = getPos(r, 0);
        var endPos = getPos(r, cols - 1);

        ctx.beginPath();
        ctx.roundRect(startPos.x - radius - 8, startPos.y - radius - 6, (cols - 1) * 60 + radius * 2 + 16, radius * 2 + 12, 10);
        ctx.stroke();
      }

      // Add helper explanation text
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('3 rows of 4 dots = 12 dots', W / 2, paddingY - 45);

      ctx.fillStyle = '#9CA3AF';
      ctx.font = '14px -apple-system, sans-serif';
      ctx.fillText('4 + 4 + 4 = 12', W / 2, H - 25);
    } else {
      // Active count text
      ctx.fillStyle = '#FBBF24';
      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('Loading: ' + Math.min(dotsToShow, totalDots) + ' / 12', W / 2, paddingY - 45);
    }
  }
};
